7	error_t ec_pve_t::encrypt(const pve_base_pke_i& base_pke, pve_keyref_t ek, mem_t label, ecurve_t curve,
8	                          const bn_t& _x) {
9	  error_t rv = UNINITIALIZED_ERROR;
10	  const auto& G = curve.generator();
11	  const mod_t& q = curve.order();
12	
13	  bn_t bn_x = _x % q;
14	  ecc_point_t Q_local = bn_x * G;
15	  buf128_t r0[kappa];
16	  buf128_t r1[kappa];
17	  buf_t c0[kappa];
18	  buf_t c1[kappa];
19	  ecc_point_t X0[kappa];
20	  ecc_point_t X1[kappa];
21	  buf_t L_local = buf_t(label);
22	  buf_t inner_label = genPVELabelWithPoint(label, Q_local);
23	  bn_t x_rows_local[kappa];
24	  buf128_t r_local[kappa];
25	  buf_t c_local[kappa];
26	
27	  for (int i = 0; i < kappa; i++) {
28	    bn_t x0, x1;
29	
30	    crypto::gen_random(r0[i]);
31	    crypto::gen_random(r1[i]);
32	    crypto::drbg_aes_ctr_t drbg0(r0[i]);
33	    crypto::drbg_aes_ctr_t drbg1(r1[i]);
34	
35	    x0 = drbg0.gen_bn(q);
36	    buf_t rho0 = drbg0.gen(rho_size);
37	
38	    MODULO(q) x1 = bn_x - x0;
39	    buf_t rho1 = drbg1.gen(rho_size);
40	
41	    if (rv = base_pke.encrypt(ek, inner_label, x0.to_bin(), rho0, c0[i])) return rv;
42	    X0[i] = x0 * G;
43	    if (rv = base_pke.encrypt(ek, inner_label, x1.to_bin(), rho1, c1[i])) return rv;
44	    X1[i] = Q_local - X0[i];
45	
46	    x_rows_local[i] = x1;  // output. will be cleared out if later bi == 0
47	  }
48	
49	  buf128_t b_local;
50	  b_local = crypto::ro::hash_string(Q_local, label, c0, c1, X0, X1).bitlen(kappa);
51	
52	  for (int i = 0; i < kappa; i++) {
53	    bool bi = b_local.get_bit(i);
54	    r_local[i] = bi ? r1[i] : r0[i];
55	    c_local[i] = bi ? c0[i] : c1[i];
56	    if (!bi) x_rows_local[i] = 0;  // clear the output
57	  }
58	
59	  Q = std::move(Q_local);
60	  L = std::move(L_local);
61	  b = b_local;
62	  for (int i = 0; i < kappa; i++) {
63	    x_rows[i] = std::move(x_rows_local[i]);
64	    r[i] = r_local[i];
65	    c[i] = std::move(c_local[i]);
66	  }
67	  return SUCCESS;
68	}
