118	error_t ec_pve_t::restore_from_decrypted(int row_index, mem_t decrypted_x_buf, ecurve_t curve, bn_t& x_value) const {
119	  const mod_t& q = curve.order();
120	  const auto& G = curve.generator();
121	  const int max_scalar_size = q.get_bin_size();
122	
123	  bool bi = b.get_bit(row_index);
124	  if (decrypted_x_buf.size > max_scalar_size) return coinbase::error(E_CRYPTO);
125	  bn_t x_bi_bar = bn_t::from_bin(decrypted_x_buf);
126	  if (!q.is_in_range(x_bi_bar)) return coinbase::error(E_CRYPTO);
127	
128	  bn_t x_bi;
129	  if (bi) {
130	    if (x_rows[row_index].get_bin_size() > max_scalar_size) return coinbase::error(E_CRYPTO);
131	    if (!q.is_in_range(x_rows[row_index])) return coinbase::error(E_CRYPTO);
132	    x_bi = x_rows[row_index];
133	  } else {
134	    crypto::drbg_aes_ctr_t drbg0(r[row_index]);
135	    x_bi = drbg0.gen_bn(q);
136	  }
137	
138	  MODULO(q) x_value = x_bi_bar + x_bi;
139	
140	  if (x_value * G != Q) {
141	    x_value = 0;
142	    return coinbase::error(E_CRYPTO);
143	  }
144	  return SUCCESS;
145	}
146	
147	error_t ec_pve_t::decrypt(const pve_base_pke_i& base_pke, pve_keyref_t dk, pve_keyref_t ek, mem_t label, ecurve_t curve,
148	                          bn_t& x_out, bool skip_verify) const {
149	  error_t rv = UNINITIALIZED_ERROR;
150	  if (!skip_verify && (rv = verify(base_pke, ek, Q, label))) return rv;
151	
152	  buf_t inner_label = genPVELabelWithPoint(label, Q);
153	
154	  for (int i = 0; i < kappa; i++) {
155	    buf_t x_buf;
156	    if (rv = base_pke.decrypt(dk, inner_label, c[i], x_buf)) continue;
157	    if (restore_from_decrypted(i, x_buf, curve, x_out) == SUCCESS) {
158	      return SUCCESS;
159	    }
160	  }
161	
162	  x_out = 0;
163	  return coinbase::error(E_CRYPTO);
164	}
