9	class ec_pve_t {
10	 public:
11	  ec_pve_t() = default;
12	
13	  const static int kappa = SEC_P_COM;
14	  const static int rho_size = 32;
15	
16	  error_t encrypt(const pve_base_pke_i& base_pke, pve_keyref_t ek, mem_t label, ecurve_t curve, const bn_t& x);
17	  error_t verify(const pve_base_pke_i& base_pke, pve_keyref_t ek, const ecc_point_t& Q, mem_t label) const;
18	  error_t decrypt(const pve_base_pke_i& base_pke, pve_keyref_t dk, pve_keyref_t ek, mem_t label, ecurve_t curve,
19	                  bn_t& x, bool skip_verify = false) const;
20	
21	  const ecc_point_t& get_Q() const { return Q; }
22	  const buf_t& get_Label() const { return L; }
23	
24	  void convert(coinbase::converter_t& converter) {
25	    converter.convert(Q, L, b);
26	    for (int i = 0; i < kappa; i++) {
27	      converter.convert(x_rows[i]);
28	      converter.convert(r[i]);
29	      converter.convert(c[i]);
30	    }
31	  }
32	
33	 private:
34	  buf_t L;
35	  ecc_point_t Q;
36	  buf128_t b;
37	
38	  bn_t x_rows[kappa];
39	  buf128_t r[kappa];
40	  buf_t c[kappa];
41	
42	  error_t restore_from_decrypted(int row_index, mem_t decrypted_x_buf, ecurve_t curve, bn_t& x_value) const;
43	};
