74	error_t ec_pve_batch_t::verify(const pve_base_pke_i& base_pke, pve_keyref_t ek, const std::vector<ecc_point_t>& Q,
75	                               mem_t label) const {
76	  error_t rv = UNINITIALIZED_ERROR;
77	  if (n <= 0 || n > MAX_BATCH_COUNT) return coinbase::error(E_BADARG);
78	  if (int(Q.size()) != n) return coinbase::error(E_BADARG);
79	
80	  // This verifies that the input Q values are the same as backed up Q values (step 2 of spec)
81	  // and that the input Q values are on curve (step 1 of spec) assuming backed up one is on curve
82	  ecurve_t curve = Q[0].get_curve();
83	  for (int i = 0; i < n; i++) {
84	    if (rv = curve.check(Q[i])) return coinbase::error(rv, "ec_pve_batch_t::verify: check Q[i] failed");
85	  }
86	  if (Q != this->Q) return coinbase::error(E_CRYPTO, "public keys (Qs) mismatch");
87	  if (label != this->L) return coinbase::error(E_CRYPTO);
88	  buf_t inner_label = genPVELabelWithPoint(label, Q);
89	
90	  const auto& G = curve.generator();
91	  const mod_t& q = curve.order();
92	  int curve_size = curve.size();
93	
94	  buf_t c0[kappa];
95	  buf_t c1[kappa];
96	  std::vector<ecc_point_t> X0[kappa];
97	  std::vector<ecc_point_t> X1[kappa];
98	
99	  for (int i = 0; i < kappa; i++) {
100	    bool bi = b.get_bit(i);
101	    // xi is x^0_i or x^1_i depends on bi == 1 or 0.
102	    // Note that we always have X[0][i] = xi * G, then X[0] and X[1] if xi is x^1_i.
103	    std::vector<bn_t> xi;
104	    if (bi) {
105	      c0[i] = rows[i].c;
106	
107	      if (rows[i].r.size() != 16) return coinbase::error(E_CRYPTO);
108	      if (rows[i].x_bin.size() != n * curve_size) return coinbase::error(E_CRYPTO);
109	      if (rv = bn_t::vector_from_bin(rows[i].x_bin, n, curve_size, q, xi)) return rv;
110	      crypto::drbg_aes_ctr_t drbg1(rows[i].r);
111	      buf_t rho1 = drbg1.gen(rho_size);
112	
113	      if (rv = base_pke.encrypt(ek, inner_label, bn_t::vector_to_bin(xi, curve_size), rho1, c1[i])) return rv;
114	    } else {
115	      c1[i] = rows[i].c;
116	
117	      if (rows[i].r.size() != 32) return coinbase::error(E_CRYPTO);
118	      crypto::drbg_aes_ctr_t drbg01(rows[i].r.take(16));
119	      buf_t x0_source_bin = drbg01.gen(n * (curve_size + coinbase::bits_to_bytes(SEC_P_STAT)));
120	      if (rv = bn_t::vector_from_bin(x0_source_bin, n, curve_size + coinbase::bits_to_bytes(SEC_P_STAT), q, xi))
121	        return rv;
122	
123	      crypto::drbg_aes_ctr_t drbg02(rows[i].r.skip(16));
124	      buf_t rho0 = drbg02.gen(rho_size);
125	
126	      if (rv = base_pke.encrypt(ek, inner_label, rows[i].r.take(16), rho0, c0[i])) return rv;
127	    }
128	
129	    X0[i].resize(n);
130	    X1[i].resize(n);
131	    for (int j = 0; j < n; j++) {
132	      X0[i][j] = xi[j] * G;
133	      X1[i][j] = Q[j] - X0[i][j];
134	    }
135	
136	    if (bi) std::swap(X0[i], X1[i]);
137	  }
138	
139	  buf_t b_tag = crypto::ro::hash_string(Q, label, c0, c1, X0, X1).bitlen(SEC_P_COM);
140	  if (b_tag != b) return coinbase::error(E_CRYPTO);
141	  return SUCCESS;
142	}
