145	  constexpr unsigned long kDefaultExponent = 65537;
146	
147	  BIGNUM* n_bn = BN_bin2bn(modulus.data, modulus.size, nullptr);
148	  if (!n_bn) return coinbase::error(E_GENERAL, "BN_bin2bn(modulus) failed");
