150	  if (BN_is_zero(n_bn)) {
151	    BN_free(n_bn);
152	    return coinbase::error(E_BADARG, "modulus must not be zero");
153	  }
154	
155	  BIGNUM* e_bn = BN_new();
156	  if (!e_bn) {
157	    BN_free(n_bn);
158	    return coinbase::error(E_GENERAL, "BN_new(e) failed");
159	  }
160	  BN_set_word(e_bn, kDefaultExponent);
