162	  coinbase::crypto::rsa_pub_key_t pk;
163	  pk.set(n_bn, e_bn);
164	  BN_free(n_bn);
165	  BN_free(e_bn);
166	
167	  base_pke_ek_blob_v1_t ek_blob;
168	  ek_blob.key_type = static_cast<uint32_t>(base_pke_key_type_v1::rsa_oaep_2048);
169	  ek_blob.rsa_ek = std::move(pk);
170	
171	  out_ek = coinbase::convert(ek_blob);
172	  return SUCCESS;
