19	struct pve_batch_ciphertext_blob_v1_t {
20	  uint32_t version = pve_batch_ciphertext_version_v1;
21	  uint32_t batch_count = 0;
22	  buf_t ct;  // serialized `coinbase::mpc::ec_pve_batch_t`
