34	static error_t parse_batch_ciphertext(mem_t ciphertext, pve_batch_ciphertext_blob_v1_t& out_blob) {
35	  error_t rv = coinbase::convert(out_blob, ciphertext);
36	  if (rv) return rv;
37	  if (out_blob.version != pve_batch_ciphertext_version_v1)
38	    return coinbase::error(E_FORMAT, "unsupported ciphertext version");
39	  if (out_blob.batch_count == 0) return coinbase::error(E_FORMAT, "invalid batch count");
40	  if (out_blob.batch_count > static_cast<uint32_t>(coinbase::mpc::ec_pve_batch_t::MAX_BATCH_COUNT))
41	    return coinbase::error(E_RANGE, "batch too large");
42	  return SUCCESS;
43	}
